using System;
using System.Collections.Generic;
using System.IO;
using Newtonsoft.Json;

class Program
{
    static void Main(string[] args)
    {
        // Read the existing JSON file into a string
        string jsonFromFile = File.ReadAllText("accounts.json");

        // Deserialize the JSON string into a list of accounts
        List<AccountsList> accountsFromFile = JsonConvert.DeserializeObject<List<AccountsList>>(jsonFromFile);

